### Pattern 4: HTTP Entry Point (`OpenAPIHandler`)

**Found in**: `/Users/jeevanpillay/Code/@lightfastai/lightfast/apps/app/src/app/(api)/v1/[...rest]/route.ts:1-56`

```ts
import { OpenAPIHandler } from "@orpc/openapi/fetch";

const handler = new OpenAPIHandler(router);

async function handleRequest(request: Request) {
  const requestId = randomUUID();
  try {
    const { matched, response } = await handler.handle(request, {
      context: { headers: request.headers, requestId },
    });
    if (matched) {
      const enriched = new Response(response.body, response);
      enriched.headers.set("X-Request-ID", requestId);
      return enriched;
    }
    return Response.json({ defined: false, code: "NOT_FOUND", status: 404, ... }, { status: 404 });
  } catch (error) {
    log.error("oRPC handler error", { error: parseError(error), requestId });
    return Response.json({ defined: false, code: "INTERNAL_SERVER_ERROR", status: 500, ... }, { status: 500 });
  }
}

export const GET = handleRequest;
export const POST = handleRequest;
// PUT, DELETE, PATCH also export handleRequest
```

**Key aspects**:
- `OpenAPIHandler` from `@orpc/openapi/fetch` — serves OpenAPI-compatible routes
- `InitialContext` (`headers`, `requestId`) is injected at `handler.handle()` call site
- `matched` boolean distinguishes "procedure found" vs "404 passthrough"
- `X-Request-ID` header appended to every matched response
- Outer try/catch for unhandled errors returns a plain 500 JSON shape with `defined: false`

